// 1. Get the data from your Webhook
const inputData = $('Webhook').first().json.body; 

// 2. Determine the Name based on Project ID or Company
const projectsArray = inputData["Projects"];
let finalClientName = "";

if (Array.isArray(projectsArray) && projectsArray.length > 0) {
    finalClientName = projectsArray[0].name;
} else {
    finalClientName = inputData["record_name"] || "Unknown Project";
}

// ---------------------------------------------------------
// 3. The Folder Checking Logic & ID Extraction
// ---------------------------------------------------------

// Find the folder object where the name matches our finalClientName
// 'items' represents the list of folders coming from your ClickUp node
const matchedFolder = items.find(item => item.json.name === finalClientName);

// If matchedFolder exists, folderExists is true, and we grab the id
const folderExists = !!matchedFolder;
const folderId = folderExists ? matchedFolder.json.id : null;

return [
  {
    json: {
      exists: folderExists,
      clientName: finalClientName,
      id: folderId, // This will contain the ClickUp Folder ID (e.g., "90147605023")
    }
  }
];
